#include<bits/stdc++.h>
using namespace std;
list<int> dq[1000005];int m,x,p;string s;
int main(void){
	cin>>m;
	for(int i=0;i<m;i++){
		cin>>s>>x;
		if(s=="push_back"){cin>>p;dq[x].push_back(p);}
		else if(s=="pop_back"&&dq[x].size()!=0)dq[x].pop_back();
		else if(s=="push_front"){cin>>p;dq[x].push_front(p);}
		else if(s=="pop_front"&&dq[x].size())dq[x].pop_front(); 
		else if(s=="size")cout<<dq[x].size()<<'\n';
		else if(s=="front"&&dq[x].size())cout<<dq[x].front()<<'\n';
		else if(s=="back"&&dq[x].size())cout<<dq[x].back()<<'\n';
	}
	return false;
}
